{"name": "write_file", "arguments": {"path": "solution.py", "content": "def binary_search(sorted_list, target):
    left = 0
    right = len(sorted_list) - 1
    while left <= right:
        mid_index = (left + right) // 2
        if sorted_list[mid_index] == target:
            return mid_index
        elif sorted_list[mid_index] < target:
            left = mid_index + 1
        else:
            right = mid_index - 1
    return -1"}}
